package obr.org.apache.karaf.obr.command;

@ Command ( scope = "obr" , name = "list" , description = "Lists OBR bundles, optionally providing the given packages." ) @ Service public class ListCommand extends ObrCommandSupport { @ Argument ( index = 0 , name = "packages" , description = "A list of packages separated by whitespaces." , required = false , multiValued = true ) List < String > packages ; @ Option ( name = "--no-format" , description = "Disable table rendered output" , required = false , multiValued = false ) boolean noFormat ; @ Override void doExecute ( RepositoryAdmin admin ) throws Exception { StringBuilder substr = new StringBuilder ( ) ; if ( packages != null ) { for ( String packageName : packages ) { substr . append ( " " ) ; substr . append ( packageName ) ; } } String query ; if ( ( substr == null ) || ( substr . length ( ) == 0 ) ) { query = "(|(presentationname=*)(symbolicname=*))" ; } else { query = "(|(presentationname=*" + substr + "*)(symbolicname=*" + substr + "*))" ; } Resource [ ] resources = admin . discoverResources ( query ) ; ShellTable table = new ShellTable ( ) ; table . column ( "Name" ) ; table . column ( "Symbolic Name" ) ; table . column ( "Version" ) ; table . emptyTableText ( "No matching bundles" ) ; for ( Resource resource : resources ) { table . addRow ( ) . addContent ( emptyIfNull ( resource . getPresentationName ( ) ) , emptyIfNull ( resource . getSymbolicName ( ) ) , emptyIfNull ( resource . getVersion ( ) ) ) ; } table . print ( System . out , ! noFormat ) ; } private String emptyIfNull ( Object st ) { return st == null ? "" : st . toString ( ) ; } }